    struct Dsu {
        parent: Vec<usize>,
        rank: Vec<usize>,
    }

    impl Dsu {
        fn new(n: usize) -> Self {
            let parent: Vec<usize> = (0..n).collect();
            let rank: Vec<usize> = vec![0; n];
            Dsu { parent, rank }
        }

        fn find(&mut self, x: usize) -> usize {
            let mut root = x;
            while self.parent[root] != root {
                root = self.parent[root];
            }
            let mut cur = x;
            while self.parent[cur] != root {
                let next = self.parent[cur];
                self.parent[cur] = root;
                cur = next;
            }
            root
        }

        fn union(&mut self, x: usize, y: usize) -> bool {
            let root_x = self.find(x);
            let root_y = self.find(y);
            if root_x == root_y {
                return false;
            }
            if self.rank[root_x] < self.rank[root_y] {
                self.parent[root_x] = root_y;
            } else if self.rank[root_x] > self.rank[root_y] {
                self.parent[root_y] = root_x;
            } else {
                self.parent[root_y] = root_x;
                self.rank[root_x] += 1;
            }
            true
        }
    }

    fn compute_components(n: usize, edges: &[Vec<i64>], t: i64) -> usize {
        let mut dsu = Dsu::new(n);
        let mut components = n;
        for edge in edges {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            let time = edge[2];
            if *time > t {
                if dsu.union(u, v) {
                    components -= 1;
                }
            }
        }
        components
    }

    let max_time = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut low: i64 = 0;
    let mut high: i64 = max_time + 1;

    while low < high {
        let mid = (low + high) / 2;
        let comp = compute_components(n as usize, &edges, mid);
        if comp >= k as usize {
            high = mid;
        } else {
            low = mid + 1;
        }
    }

    low
}
